import React, { useState, useEffect, useRef, useMemo } from 'react';
import { motion, useAnimationFrame } from 'framer-motion';
import { Case } from '../data/cases';
import { Game } from '../data/games';

interface OpeningAnimationProps {
  caseData: Case;
  onComplete: (result: { game: Game; key: string }) => void;
}

// Определяем редкость на основе цены игры (для цвета свечения)
const getRarityColor = (price: number): string => {
  if (price >= 2000) return '#ffaa00'; // золотой
  if (price >= 1000) return '#ff5500'; // оранжевый
  if (price >= 500) return '#aa00ff';  // фиолетовый
  if (price >= 200) return '#0055ff';  // синий
  return '#ffffff';                     // обычный
};

const OpeningAnimation: React.FC<OpeningAnimationProps> = ({ caseData, onComplete }) => {
  const games = caseData.games;

  // Состояния анимации
  const [phase, setPhase] = useState<'caseAppear' | 'keyInsert' | 'lidOpen' | 'spinning' | 'slowdown' | 'stop' | 'itemReveal'>('caseAppear');
  const [selectedGame, setSelectedGame] = useState<Game | null>(null);
  const [scrollOffset, setScrollOffset] = useState(0);
  const [scrollSpeed, setScrollSpeed] = useState(0); // пикселей за кадр
  const itemsRef = useRef<HTMLDivElement>(null);

  // Генерация последовательности для прокрутки (с весами)
  const weightedSequence = useMemo(() => {
    if (!games.length) return [];
    const maxPrice = Math.max(...games.map(g => g.price_rub));
    const weights = games.map(g => Math.pow(maxPrice / (g.price_rub || 1), 2));
    const totalWeight = weights.reduce((a, b) => a + b, 0);
    const length = 200;
    const seq: Game[] = [];
    for (let i = 0; i < length; i++) {
      const rand = Math.random() * totalWeight;
      let acc = 0;
      for (let j = 0; j < games.length; j++) {
        acc += weights[j];
        if (rand < acc) {
          seq.push(games[j]);
          break;
        }
      }
    }
    return seq;
  }, [games]);

  // Выбор выигрышной игры
  const winningGame = useMemo(() => {
    // Случайный выбор с учётом весов (аналогично)
    if (!games.length) return null;
    const maxPrice = Math.max(...games.map(g => g.price_rub));
    const weights = games.map(g => Math.pow(maxPrice / (g.price_rub || 1), 2));
    const totalWeight = weights.reduce((a, b) => a + b, 0);
    const rand = Math.random() * totalWeight;
    let acc = 0;
    for (let i = 0; i < games.length; i++) {
      acc += weights[i];
      if (rand < acc) return games[i];
    }
    return games[0];
  }, [games]);

  // Управление фазами
  useEffect(() => {
    if (phase === 'caseAppear') {
      const timer = setTimeout(() => setPhase('keyInsert'), 2000);
      return () => clearTimeout(timer);
    }
    if (phase === 'keyInsert') {
      const timer = setTimeout(() => setPhase('lidOpen'), 1500);
      return () => clearTimeout(timer);
    }
    if (phase === 'lidOpen') {
      const timer = setTimeout(() => setPhase('spinning'), 1500);
      return () => clearTimeout(timer);
    }
    if (phase === 'spinning') {
      setScrollSpeed(15); // начальная скорость
      const timer = setTimeout(() => setPhase('slowdown'), 3000);
      return () => clearTimeout(timer);
    }
    if (phase === 'slowdown') {
      // скорость будет уменьшаться в useAnimationFrame
    }
    if (phase === 'stop') {
      setScrollSpeed(0);
      const timer = setTimeout(() => setPhase('itemReveal'), 500);
      return () => clearTimeout(timer);
    }
    if (phase === 'itemReveal') {
      setSelectedGame(winningGame);
      const timer = setTimeout(() => {
        const key = generateFakeKey();
        onComplete({ game: winningGame!, key });
      }, 2000);
      return () => clearTimeout(timer);
    }
  }, [phase, winningGame]);

  // Анимация прокрутки с замедлением
  useAnimationFrame((time, delta) => {
    if (phase === 'spinning' || phase === 'slowdown') {
      if (phase === 'slowdown') {
        setScrollSpeed(prev => Math.max(0, prev - 0.1)); // замедление
        if (scrollSpeed <= 0.1) {
          setPhase('stop');
        }
      }
      setScrollOffset(prev => (prev + scrollSpeed) % (weightedSequence.length * 120));
    }
  });

  const generateFakeKey = () => {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    const segment = () => Array(5).fill(0).map(() => chars[Math.floor(Math.random() * chars.length)]).join('');
    return `${segment()}-${segment()}-${segment()}-${segment()}-${segment()}`;
  };

  return (
    <div className="opening-container">
      {/* 3D сцена */}
      <div className="scene-3d">
        {/* Кейс */}
        <motion.div
          className="case-3d"
          initial={{ scale: 0, rotateY: 0, rotateX: 0 }}
          animate={
            phase === 'caseAppear'
              ? { scale: 1, rotateY: [0, 360], transition: { duration: 2, ease: 'easeOut' } }
              : phase === 'keyInsert'
              ? { rotateY: 0, rotateX: 10, y: -20, transition: { duration: 1.5 } }
              : phase === 'lidOpen'
              ? { rotateX: 0, y: 0, transition: { duration: 1 } }
              : { scale: 0.5, opacity: 0, transition: { duration: 0.5 } }
          }
        >
          {/* Визуализация кейса */}
          <div className="case-body">
            <div className="case-lid"></div>
            <div className="case-bottom"></div>
          </div>
        </motion.div>

        {/* Ключ (появляется при keyInsert) */}
        {phase === 'keyInsert' && (
          <motion.div
            className="key-3d"
            initial={{ x: 200, opacity: 0 }}
            animate={{ x: 0, opacity: 1, rotate: [0, -10, 0], transition: { duration: 1, ease: 'easeOut' } }}
          />
        )}

        {/* Крышка открывается */}
        {phase === 'lidOpen' && (
          <motion.div
            className="case-lid-open"
            initial={{ rotateX: 0, originY: 0 }}
            animate={{ rotateX: -120, transition: { duration: 1, ease: 'easeOut' } }}
          />
        )}

        {/* Колесо предметов (появляется при spinning) */}
        {(phase === 'spinning' || phase === 'slowdown' || phase === 'stop') && (
          <div className="spinning-items-container">
            <motion.div
              ref={itemsRef}
              className="spinning-items"
              style={{ x: -scrollOffset }}
            >
              {weightedSequence.map((game, idx) => (
                <div key={idx} className="spinning-item">
                  <img src={game.bannerUrl} alt={game.name} />
                  <span>{game.name.slice(0, 10)}...</span>
                </div>
              ))}
            </motion.div>
            <div className="selector-line" />
          </div>
        )}

        {/* Вылет предмета */}
        {phase === 'itemReveal' && selectedGame && (
          <motion.div
            className="item-reveal"
            initial={{ scale: 0, opacity: 0, y: 0 }}
            animate={{ scale: 2, opacity: 1, y: -50, transition: { duration: 0.8, ease: 'easeOut' } }}
            style={{ boxShadow: `0 0 50px ${getRarityColor(selectedGame.price_rub)}` }}
          >
            <img src={selectedGame.bannerUrl} alt={selectedGame.name} />
            <h3>{selectedGame.name}</h3>
          </motion.div>
        )}
      </div>

      {/* Свечение в зависимости от редкости */}
      {phase === 'itemReveal' && selectedGame && (
        <motion.div
          className="rarity-glow"
          initial={{ opacity: 0 }}
          animate={{ opacity: [0.5, 1, 0.5], scale: [1, 1.2, 1] }}
          transition={{ duration: 2, repeat: Infinity }}
          style={{ background: `radial-gradient(circle, ${getRarityColor(selectedGame.price_rub)} 0%, transparent 70%)` }}
        />
      )}
    </div>
  );
};

export default OpeningAnimation;
